      practiceType,
      advancedMode,
      fretboardSystem,
      shape,
      shapeNotes,
      shapeDisplayName,
      cagedShape: advancedMode ? (data.get('cagedShape') || 'C') : 'C',
      // strum_comp voicing controls (pathway-driven hidden fields). voicingPosition
