      sequence: advancedMode ? (data.get('sequence') || 'none') : 'none',
      harmonize: data.get('harmonize') === 'on',   // twin-guitar thirds/sixths (§2.4)
      tremolo: data.get('tremolo') === 'on',        // mark generated notes tremolo-picked (melodeath/death)
