        await loadScriptOnce('virtuoso-waf-player', WAF_PLAYER_URL);
        if (typeof WebAudioFontPlayer === 'undefined') throw new Error('WebAudioFontPlayer missing');
        if (!wafPlayer) wafPlayer = new WebAudioFontPlayer();
