    const ap = cfgAudioProfile(cfg);
    if (ap && DRUMLESS_PROFILES.has(ap)) return null;
    if (cfg.swing === 'shuffle') return 'shuffle_blues';
    const byProf = ap && GROOVE_FOR_PROFILE[ap];
    if (byProf && DRUM_GROOVES[byProf]) return byProf;
