    const jam = isJamMode();
    const cycN = jam ? (activeBundle.config?.bars || 0) : 0;
    const seam = seamCountInfo();   // mid count-in / break / resume runway? (suppresses the loop hint; drawn as a readout last)

    // Loop-zone backing + base track
