    ctx.strokeStyle = 'rgba(148,163,184,0.18)'; ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(0, lz + 0.5); ctx.lineTo(W, lz + 0.5); ctx.stroke();

