  function rigIdbPut(id, ab) { return rigDb().then(db => new Promise((res, rej) => { const tx = db.transaction('irs', 'readwrite'); tx.objectStore('irs').put(ab, id); tx.oncomplete = () => res(); tx.onerror = () => rej(tx.error); })); }
