    if (!opens || !opens.length) return;
    _tunerTargets = opens.map((midi) => ({ midi, name: NOTE_NAMES[((midi % 12) + 12) % 12] + (Math.floor(midi / 12) - 1) }));
    _tunerHold = { idx: -1, count: 0 }; _tunerLocked = new Set();
