    const tail = [`Practiced ${m.dur}`];
    if (s.streak > 0) tail.push(`Day ${s.streak}`);
    if (!xpOff) { try { const lv = xpLevelInfo(progressLoad().xp); tail.push(`Level ${lv.level} · ${lv.name}`); } catch (_) {} }
